//换行公式对齐
{lll}:三列分别左对齐

\begin{displaymath}
    \begin{array}{lll}
&amp;&amp;a+a+a+a+a+a+a+a\\
&amp;=&amp;a+a+a+a+a+a+a+a.
    \end{array}
\end{displaymath}

//(第一列)&amp;(第二列)&amp;(第三列)：表示第一行的前两列为空，第三列才开始填充内容
//&amp;=：表示 = 处于第二列，右侧的表达式在第三列

//行间距
\renewcommand*{\arraystretch}{1.5} //1.5倍行距
\begin{displaymath}
    \begin{array}{lll}
...
